INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00316', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「我們擔心的，不只是『取之有盡，用之有竭』的環保觀念被輕忽，更憂心的是，對物的不知珍惜，將 導致人際間的不相親，視接受為理所當然，從不去檢視紫陌紅塵中的緣會到底代表了什麼意義，而徒 嘆人情澆薄。社會競爭太厲害了，人們為了勇往直前，養成了隨用隨丟的習慣，行囊裡不願裝置負擔， 固然有利前進的腳步，但當我們停步歇息時，羞澀的行囊，又能提供那些可供咀嚼回味的糧食呢？當 人人都只追求現實利益，不再珍攝彼此的情分，這世界將變得如何教人傷心啊！」 下列選項，何者最符合上文旨意？', '["體內環保", "惜物惜緣", "真情無價", "紅塵行旅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00317', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「全民戴口罩防疫，守住健康，卻遮住人們說話的表情和嘴型，也意外將仰賴唇語溝通的聽損者，關 入難以對外交流的孤島。為此，蒲公英聽語協會催生了全臺首片『透明口罩』。」 根據上篇報導，透明口罩的催生，符合下列何種精神？', '["天聽自我民聽", "敏於事，慎於言", "人溺己溺，人飢己飢", "多言數窮，不如守中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00318', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「大家一方面重砲抨擊公務員，另一方面卻認為公務員是個好職業。到底，當公務員好不好？如果說 這是個好職業，那為什麼又常常是眾矢之的？這很根本的，涉及了考公職的心態是什麼。曾經聽過一 位任職公門，後轉教界全力推動生態旅遊的老師提及，當初考進公職時，是認為在政府有資源可以做 想做的事情，可以對社會產生影響。但是，現在的人考公職，似乎是為了求個穩定，對於服務社會的 動機，好像變薄弱了。」 根據上文，作者認為投入公職本應為了什麼原因？', '["薪水的多寡", "服務的精神", "異動的自由", "他人的評價"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00319', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「六○年代開始，亞洲在二次世界大戰後逐步復甦，戰敗的日本在美國援助下重建經濟，積極發展重 工業。汽車、電子產品快速成長，日本各大企業迅速崛起，『Made inJapan』是亞洲經濟起飛的第一 步。隨著日本經濟快速地成長，成本跟著高漲，產業版圖位移，美國尋找新的合作夥伴。七○年代， 機會的雲朵來到了臺灣的上空。當時中國與西方世界對立，政策封閉；越南剛打完越戰，百廢待舉； 其他的東南亞國家，如菲律賓、馬來西亞，政經情勢尚未安定，問題層出不窮……，香港、新加坡固 然不錯，但腹地太小，無法發展工業。於是，機會便翩然降臨到腹地最大、人口最多、勞力最密集且 便宜的臺灣。那時的臺灣人很爭氣，即使沒有邦交，仍勇敢提著手提箱走向世界，這種『一卡皮箱』 的精神，讓臺灣人牢牢握住成為世界舞臺要角的機會，也造就『MadeinTaiwan』世界工廠的巔峰。 此後短短三十年間，臺灣一路由傳統的農業出口、製造業出口之後，轉而邁向科技出口三階段，形成 美國是『設計的頭腦』，而臺灣則是那雙『代工的手』，也成就日後『臺灣矽谷』美名。」 根據上文，下列選項何者正確？', '["臺灣曾有的太平盛世是自六○年代開始", "八○年代臺灣繼日本成為亞洲第二個經濟起飛地區", "「臺灣矽谷」的美名成就於臺灣製造業出口的階段", "臺灣由農業轉向製造業，繼而逐漸改變為科技業出口"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00320', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「對人體最有幫助的巧克力，就是黑巧克力，除了比較沒有糖分之外，也較貼近可可原本的風味。英 國研究顯示，老年人每日食用3.5盎司的黑巧克力，確實會降低罹患心臟疾病的機率。」 依據上文，想要對健康有正向幫助，下列何者不是挑選巧克力最重要的考量？', '["種類", "份量", "添加物", "食用年齡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00321', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「生命的困惑是個人文問題，但是人文之所以會瓦解是因為科學的壓迫。站在二十一世紀，想要重振 人文精神，同時抵敵科學的壓迫，非得要一個人同時跨越人文與理工不可——要自己去浸淫才有機會 深刻地了解人文，要有能力洞穿科學才有辦法真正地知道它的極限。」 下列最能表達此段文字主張的選項是：', '["二十一世紀應專注於人文教育", "生命的困惑源自於科學的發展", "科學的壓迫導致人類更加迷惘", "當代人須兼具人文與科學素養"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00322', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「書籍是根據特定架構、有系統地將同一主題的資訊蒐集整理的文本。想要窮通任何領域的知識，書 籍才是根本，報章雜誌網路文章只是輔佐，用來更新最新資訊或個案狀況。專業工作者需要先具備解 讀資訊的架構與問題意識，閱讀網路資訊才能讀出所以然，而書籍仍是累積專業知識架構與思考分析 方法最有效且最好用的工具。」 依據上文，最適切的標題是：', '["網路資訊有助知識建構", "書籍有利建構專業職能", "專業知識奠基領域分工", "問題意識有益融會貫通"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00323', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「我們幾乎從未想過這麼做要付出什麼代價。儘管低頭看手機（不管是和他人聊天或查看網站數據） 讓人滿足，因為它是具體而有目標的活動。如果在同樣這段時間裡，什麼都不做，只是處在當下，張 開雙眼，敞開心靈，也許有人就會感覺茫然不知所措，因為他不知如何面對這段空檔裡的自己。其實， 脫離訊息之流，真正活在當下，對追求創意的靈感和表現，是不可或缺的。想想詩人藝術家茱莉亞‧ 卡麥隆（JuliaCameron）曾說的『注滿內心的創意之井』。你想不到的是，當我們關掉一種刺激時，同 時也會接受到另一種刺激。」 下列敘述，符合上文之意的是：', '["「接受到另一種刺激」指的是：創意與靈感的泉湧", "「關掉一種刺激」指的是：不理會外界對手機的批評", "「接受到另一種刺激」指的是：生活失焦不安，沒有重心", "「關掉一種刺激」指的是：尋覓遺世獨立的桃花源，最後離群索居"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00324', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「人有人趣，物有物趣，自然景物有天趣。顧凝遠論畫，就是以天趣、物趣、人趣包括一切。能夠瀟洒 出羣，靜觀宇宙人生，知趣了，才可以畫畫。名、利、色、權，都可以把人弄得神魂不定。只這趣字， 是有益身心的。就做到如米顛或黃大痴，也沒有什麼大害處。人生必有痴，必有偏好癖嗜。沒有癖嗜 的人，大半靠不住。而且就變為索然無味的不知趣的一個人了。」 下列選項，何者最貼近上文旨意？', '["宇宙人生萬物皆有其趣", "名利色權大多違反天趣", "知趣成痴之人值得信賴", "須有癖嗜才能從事創作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00325', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列輓詞：「甘棠遺愛」、「風冷杏壇」、「痛失陶朱」、「后稷同功」。祭奠的對象身分依順序是：', '["農界、學界、工業界、商界", "商界、醫界、工業界、政界", "政界、教育界、商界、農界", "醫界、教育界、農界、商界"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
